// IELTS vocabulary library, organised by CEFR level (B2 / C1 / C2).
//
// The word data lives in b2.json / c1.json / c2.json and is generated by
// `node scripts/generate-vocab.mjs` from public CEFR word lists + the Free
// Dictionary API + machine translation. Each entry:
//   { id, level, word, phonetic, pos, definition, zh, example, exampleZh }
// Re-run the script to regenerate / expand the lists.

import b2 from './b2.json'
import c1 from './c1.json'
import c2 from './c2.json'

export const VOCAB = { B2: b2, C1: c1, C2: c2 }

export const LEVELS = [
  { id: 'B2', name: 'B2 · Upper-Intermediate', blurb: '進階基礎：勝任日常與學術討論的核心詞彙', target: 'IELTS 5.5 – 6.5' },
  { id: 'C1', name: 'C1 · Advanced', blurb: '進階學術：表達抽象觀點與論證的詞彙', target: 'IELTS 7.0 – 7.5' },
  { id: 'C2', name: 'C2 · Proficiency', blurb: '精通母語級：細膩、精準、地道的高階詞彙', target: 'IELTS 8.0+' }
]

export const ALL_WORDS = [...VOCAB.B2, ...VOCAB.C1, ...VOCAB.C2]

export function wordById(id) {
  return ALL_WORDS.find((w) => w.id === id)
}
